def sync_articles_to_db(
        session: Session, website_id: int, url_file_mapping: dict[str, str]
):
    """Insert all articles into database"""
    for url, file_path in url_file_mapping.items():
        # print(f"Inserting {url} -> {file_path}")
        if file_path:  # Only if file exists
            existing = session.exec(
                select(Article).where(
                    Article.file_path == file_path,
                    Article.website_id == website_id
                )
            ).first()
            if not existing:
                insert_article(session, website_id, file_path, url=url)


# %% ../nbs/09_seo_report.ipynb #24bd6d69
def find_duplicate_metadata(
        session: Session, field: str, website_id: int, similarity_threshold: float = 0.9,
) -> list[dict]:
    """Find pages with duplicate or very similar metadata fields"""
    from seo_rat.content_parser import parse_metadata, calculate_similarity

    articles = session.exec(select(Article).where(Article.website_id == website_id)).all()
    values = {}

    # Collect all field values
    for article in articles:
        with open(article.file_path, "r") as f:
            if article.file_path.endswith(".ipynb"):
                metadata = parse_notebook_metadata(f.read())
                values[article.file_path] = metadata.get(field, "")
            elif article.file_path.endswith(".md") or article.file_path.endswith(
                    ".qmd"
            ):
                metadata = parse_metadata(f.read())
                values[article.file_path] = metadata.get(field, "")

    # Find duplicates
    duplicates = []
    checked = set()

    for path1, field1 in values.items():
        for path2, field2 in values.items():
            if path1 >= path2 or (path1, path2) in checked:
                continue
            if not field1 or not field2:
                continue

            similarity = calculate_similarity(field1, field2)
            if similarity >= similarity_threshold:
                duplicates.append(
                    {
                        "file1": path1,
                        "file2": path2,
                        f"{field}_1": field1,
                        f"{field}_2": field2,
                        "similarity": similarity,
                    }
                )
            checked.add((path1, path2))

    return duplicates


